        .app-container{display:flex;flex-direction:column;min-height:100vh;}
        .header{background: linear-gradient(135deg, var(--primary), var(--primary-dark), #ffa726);padding:20px 30px;display:flex;justify-content:space-between;align-items:center;box-shadow:0 4px 20px rgba(0,0,0,0.3);position:relative;}
