        .upload-subtitle{font-size:18px;color:#999;margin-bottom:30px;line-height:1.6;}
        .upload-btn{padding:18px 40px;background: linear-gradient(135deg, var(--primary), var(--primary-dark));border:none;border-radius:30px;color:white;font-weight:700;font-size:18px;cursor:pointer;transition:all 0.3s ease;text-transform:uppercase;letter-spacing:1px;box-shadow:0 8px 25px rgba(255,107,107,0.3);}
