<body>
    <div class="app-container">
        <div class="header">
            <div class="logo"><h1>ProEdit Studio</h1></div>
        </div>
        <div class="workspace">
            <div class="canvas-area">
                <div class="canvas-container">
                    <div class="upload-zone" id="uploadZone">
                        <div class="upload-icon">📁</div>
                        <div class="upload-title">Drag & Drop Image</div>
                        <div class="upload-subtitle">or click the button below to upload</div>
                        <button class="upload-btn" id="uploadBtn">Upload Image</button>
                        <input type="file" id="imageInput" accept="image/*">
                    </div>
                    <div class="canvas-wrapper" id="canvasWrapper">
                        <canvas id="mainCanvas"></canvas>
                    </div>
                </div>
            </div>
        </div>
    </div>

    <script>
        const uploadZone = document.getElementById('uploadZone');
        const imageInput = document.getElementById('imageInput');
        const uploadBtn = document.getElementById('uploadBtn');
        const canvasWrapper = document.getElementById('canvasWrapper');
        const mainCanvas = document.getElementById('mainCanvas');
        const ctx = mainCanvas.getContext('2d');

        // Click button opens file selector
        uploadBtn.addEventListener('click', () => imageInput.click());

        // Drag & drop
        uploadZone.addEventListener('dragover', e => {
            e.preventDefault();
            uploadZone.classList.add('dragover');
        });
        uploadZone.addEventListener('dragleave', e => {
            e.preventDefault();
            uploadZone.classList.remove('dragover');
        });
        uploadZone.addEventListener('drop', e => {
            e.preventDefault();
            uploadZone.classList.remove('dragover');
            const file = e.dataTransfer.files[0];
            if(file) loadImage(file);
        });

        // File input
        imageInput.addEventListener('change', e => {
            const file = e.target.files[0];
            if(file) loadImage(file);
        });

        function loadImage(file){
            const reader = new FileReader();
            reader.onload = e => {
                const img = new Image();
                img.onload = () => {
                    mainCanvas.width = img.width;
                    mainCanvas.height = img.height;
                    ctx.drawImage(img,0,0);
                    canvasWrapper.style.display = 'block';
                    uploadZone.style.display = 'none';
                }
                img.src = e.target.result;
            }
            reader.readAsDataURL(file);
        }
    </script>
</body>
</html>
