function colorDistance(c1,c2){return Math.sqrt((c1[0]-c2[0])**2+(c1[1]-c2[1])**2+(c1[2]-c2[2])**2);}

function createMask(sample,tol){
  let mask=[];
  for(let y=0;y<canvas.height;y++){
    let row=[];
    for(let x=0;x<canvas.width;x++){
      let idx=(y*canvas.width+x)*4;
      let px=[imgData.data[idx],imgData.data[idx+1],imgData.data[idx+2]];
      row.push(colorDistance(px,sample)<=tol?1:0);
    }
    mask.push(row);
  }
  return mask;
}

function marchingSquares(mask){
  let points=[];
  for(let y=0;y<mask.length;y++){
    for(let x=0;x<mask[0].length;x++){
      if(mask[y][x]) points.push([x,y]);
    }
  }
  return points;
}

function simplifyPath(points,epsilon=2){
  if(points.length<3) return points;
  let dmax=0,index=0;
  function perp(pt,start,end){let dx=end[0]-start[0],dy=end[1]-start[1];return Math.abs(dy*pt[0]-dx*pt[1]+end[0]*start[1]-end[1]*start[0])/Math.sqrt(dx*dx+dy*dy);}
  for(let i=1;i<points.length-1;i++){let d=perp(points[i],points[0],points[points.length-1]);if(d>dmax){dmax=d;index=i;}}
  if(dmax>epsilon){
    let rec1=simplifyPath(points.slice(0,index+1),epsilon);
    let rec2=simplifyPath(points.slice(index),epsilon);
    return rec1.slice(0,-1).concat(rec2);
  }else return [points[0],points[points.length-1]];
}

document.getElementById('imageInput').addEventListener('change',function(e){
