const shadeInput = document.getElementById('shadeTolerance');
const simplifyInput = document.getElementById('simplifyPath');
const toleranceDisplay = document.getElementById('toleranceValue');
const simplifyDisplay = document.getElementById('simplifyValue');

function resizeCanvas(img){
  const maxW = 460, maxH = 400;
  let w = img.width, h = img.height;
  const ratio = Math.min(maxW/w, maxH/h, 1);
  w*=ratio; h*=ratio;
  canvas.width = overlay.width = w;
  canvas.height = overlay.height = h;
  ctx.drawImage(img,0,0,w,h);
  imgData = ctx.getImageData(0,0,w,h);
}

document.getElementById('imageInput').addEventListener('change',e=>{
  if(e.target.files && e.target.files[0]){
    const reader = new FileReader();
