}

function distance(c1,c2){
  return Math.sqrt(Math.pow(c1[0]-c2[0],2)+Math.pow(c1[1]-c2[1],2)+Math.pow(c1[2]-c2[2],2));
}

canvas.addEventListener('click', e=>{
  if(!imgData) return;
  const rect = canvas.getBoundingClientRect();
  const x = Math.floor((e.clientX-rect.left)*canvas.width/rect.width);
  const y = Math.floor((e.clientY-rect.top)*canvas.height/rect.height);
  const color = getPixel(x,y);
  selectedColors.push(color);
  octx.fillStyle = '#f00'; octx.strokeStyle='#fff'; octx.lineWidth=2;
  octx.beginPath(); octx.arc(x,y,6,0,2*Math.PI); octx.fill(); octx.stroke();
});

shadeInput.addEventListener('input',()=>toleranceDisplay.textContent=shadeInput.value);
simplifyInput.addEventListener('input',()=>simplifyDisplay.textContent=simplifyInput.value);

function processImage(){
  if(!imgData || selectedColors.length===0) return;
  const mask = new Uint8ClampedArray(imgData.width*imgData.height);
  const tol = parseInt(shadeInput.value);
  for(let y=0;y<imgData.height;y++){
    for(let x=0;x<imgData.width;x++){
      const p = getPixel(x,y);
      for(const c of selectedColors){
        if(distance(p,c)<=tol){ mask[y*imgData.width+x]=1; break; }
      }
    }
  }
  const objCanvas = document.createElement('canvas');
  objCanvas.width=canvas.width; objCanvas.height=canvas.height;
  const octx2=objCanvas.getContext('2d');
  const imgOut=octx2.createImageData(canvas.width,canvas.height);
  for(let i=0;i<mask.length;i++){
    const idx=i*4;
    if(mask[i]){
      imgOut.data[idx]=imgData.data[idx];
      imgOut.data[idx+1]=imgData.data[idx+1];
      imgOut.data[idx+2]=imgData.data[idx+2];
      imgOut.data[idx+3]=255;
    }
  }
  octx2.putImageData(imgOut,0,0);
  const dataURL = objCanvas.toDataURL('image/png');
  objects.push({canvas: objCanvas, png:dataURL});
