.canvas-card{flex:1;min-width:260px;background:#fff;border-radius:10px;padding:10px;box-shadow:0 6px 18px rgba(0,0,0,0.06)}
#canvas{width:100%;height:auto;display:block;border-radius:6px}
.overlay{position:relative}
.overlay canvas{position:absolute;left:0;top:0;pointer-events:none}
.slider{width:100%}
.row{display:flex;gap:8px;align-items:center}
.label{font-size:13px;color:var(--muted)}
.tools{display:flex;gap:8px;flex-wrap:wrap;align-items:center}
.status{padding:10px;text-align:center;color:#234;border-radius:8px;background:#e8f4ff;margin:12px}
.suggestions{display:flex;gap:8px;flex-wrap:wrap}
.suggestion{background:#f7f7f8;padding:8px;border-radius:8px;min-width:120px}
.object-list{display:flex;gap:8px;flex-wrap:wrap;margin-top:12px}
.thumb{width:110px;border-radius:8px;background:#fff;padding:6px;box-shadow:0 6px 18px rgba(0,0,0,0.06);text-align:center}
.thumb img{width:100%;height:auto;border-radius:6px}
.switch{display:inline-flex;align-items:center;gap:8px}
.small-muted{font-size:12px;color:#666}
.footer{padding:12px;text-align:center;font-size:13px;color:#555}
input[type=file]{display:none}
input[type=color]{height:36px;padding:0;border-radius:6px;border:1px solid #ddd}
.toggle{display:inline-flex;align-items:center;gap:6px}
.dashed{stroke-dasharray:6 6}
</style>
</head>
<body>
<div class="app" id="app">
  <div class="header">
    <h1>Vinyl Sticker Cutter — Pro</h1>
    <div class="small-muted">Tap to sample • Shade-aware selection • Smart suggestions • SVG + PNG export</div>
  </div>

  <div class="top">
    <div style="display:flex;gap:8px;align-items:center;">
      <label class="btn small" for="fileInput">📷 Choose Image</label>
      <input id="fileInput" type="file" accept="image/*">
      <button id="undoBtn" class="btn ghost small">↶ Undo</button>
      <button id="clearBtn" class="btn ghost small">Clear</button>
    </div>

    <div class="controls">
      <div>
        <div class="label">Color picker</div>
        <div style="display:flex;gap:8px;margin-top:6px;align-items:center">
          <input id="colorPicker" type="color" value="#ff0000">
          <div style="flex:1">
            <div class="label">Shade tolerance <span id="tolVal">30</span></div>
            <input id="tolerance" class="slider" type="range" min="4" max="120" value="30">
          </div>
        </div>
      </div>

      <div>
        <div class="label">Minimum size (px) <span id="minVal">80</span></div>
        <input id="minSize" class="slider" type="range" min="10" max="2000" value="80">
        <div class="label" style="margin-top:8px">Edge smoothing <span id="edgeVal">2</span></div>
        <input id="edgeSmooth" class="slider" type="range" min="0" max="8" value="2">
      </div>

      <div>
        <div class="label">Vector smoothing (optional)</div>
        <div style="display:flex;gap:8px;align-items:center;margin-top:6px">
          <label class="toggle"><input id="vecToggle" type="checkbox"> Advanced</label>
          <div style="flex:1">
            <div class="label">Smooth level <span id="vecVal">50%</span></div>
            <input id="vecLevel" class="slider" type="range" min="0" max="100" value="50">
          </div>
        </div>
        <div style="margin-top:8px">
          <label><input id="mergeToggle" type="checkbox" checked> Merge all selected into 1 object</label>
        </div>
      </div>

      <div>
        <div class="label">Smart Suggest</div>
        <div style="display:flex;gap:8px;align-items:center;margin-top:6px">
          <label class="label">Overlay opacity <span id="suggOp">0.45</span></label>
        </div>
        <input id="suggOpacity" class="slider" type="range" min="0" max="1" step="0.05" value="0.45">
        <div style="margin-top:8px">
          <div class="label">Dashed outline thickness</div>
          <input id="dashThick" class="slider" type="range" min="1" max="8" value="2">
        </div>
      </div>
    </div>
  </div>

  <div class="panel">
    <div class="canvas-wrap">
      <div class="canvas-card">
        <div class="label">Image</div>
        <div class="overlay" id="canvasHolder">
          <canvas id="mainCanvas"></canvas>
          <canvas id="overlayCanvas" style="position:absolute;left:0;top:0;"></canvas>
        </div>
        <div style="margin-top:8px;display:flex;gap:8px;align-items:center;flex-wrap:wrap">
          <button id="processBtn" class="btn small">⚡ Process (Suggest)</button>
          <button id="acceptAllBtn" class="btn small ghost">Accept All</button>
          <button id="rejectAllBtn" class="btn small ghost">Reject All</button>
        </div>
      </div>

      <div class="canvas-card">
        <div class="label">Suggestions & Objects</div>
        <div id="suggestions" class="suggestions" style="margin-top:8px"></div>
        <div class="label" style="margin-top:10px">Final Objects</div>
        <div class="object-list" id="objectList"></div>
      </div>
    </div>

    <div class="status" id="status">Load an image and tap to sample colors.</div>

    <div style="display:flex;gap:8px;align-items:center;padding:12px">
      <div style="flex:1">
        <label class="label">Export background</label>
        <select id="bgSelect">
          <option value="transparent">Transparent</option>
          <option value="white">White</option>
        </select>
      </div>
      <div style="display:flex;gap:8px">
        <button id="downloadSVG" class="btn small">💾 Download SVG</button>
        <button id="downloadPNG" class="btn small">💾 Download PNG</button>
      </div>
    </div>

  </div>

  <div class="footer">Made offline — save images directly to your device. Smart suggestions are just suggestions — accept what you want.</div>
</div>

<script>
/* ========= Utility functions ========= */
function rgbToHsv(r,g,b){
  r/=255; g/=255; b/=255;
  const max=Math.max(r,g,b), min=Math.min(r,g,b);
  const d=max-min;
  let h=0, s = max === 0 ? 0 : d/max;
  if(d!==0){
    if(max===r) h = (g-b)/d + (g<b?6:0);
    else if(max===g) h = (b-r)/d + 2;
    else h = (r-g)/d + 4;
    h /= 6;
  }
  return [h*360, s*100, max*100];
}
function hexToRgb(hex){
  if(hex[0]==='#') hex=hex.slice(1);
  return [parseInt(hex.slice(0,2),16), parseInt(hex.slice(2,4),16), parseInt(hex.slice(4,6),16)];
}
function clamp(v,a,b){return Math.max(a,Math.min(b,v));}

/* ======== Marching squares edge tracer (basic) ========
   We implement a simple border-following algorithm on a binary mask.
   Returns array of contours (each is array of [x,y]).
*/
function maskToContours(mask, w, h){
  // mask: Uint8Array length w*h, 0 or 1
  const visited = new Uint8Array(w*h);
  const contours = [];
  const idx = (x,y)=>y*w+x;
  const neighbors = [[1,0],[0,1],[-1,0],[0,-1]];

  function bfs(x0,y0){
    const queue=[[x0,y0]];
    visited[idx(x0,y0)] = 1;
    const pixels = [];
    while(queue.length){
      const [x,y] = queue.pop();
      pixels.push([x,y]);
      for(const [dx,dy] of neighbors){
        const nx=x+dx, ny=y+dy;
        if(nx>=0 && nx<w && ny>=0 && ny<h){
          const i=idx(nx,ny);
          if(mask[i] && !visited[i]){ visited[i]=1; queue.push([nx,ny]); }
        }
      }
    }
    return pixels;
  }

  for(let y=0;y<h;y++){
    for(let x=0;x<w;x++){
      const i = idx(x,y);
      if(mask[i] && !visited[i]){
        const pixels = bfs(x,y);
        // trace boundary: pick outer boundary via simple convex hull on pixels
        // convert pixels to points and compute simple contour via alpha-shape? For speed: compute convex hull then refine.
        // compute 2D convex hull (Monotone chain)
        // convert points to unique set of [x,y]
        const pts = pixels.map(p => [p[0], p[1]]);
        // compute convex hull
        pts.sort((a,b)=> a[0]===b[0]? a[1]-b[1] : a[0]-b[0]);
        const cross = (o,a,b) => (a[0]-o[0])*(b[1]-o[1]) - (a[1]-o[1])*(b[0]-o[0]);
        const lower = [];
        for(const p of pts){
          while(lower.length>=2 && cross(lower[lower.length-2], lower[lower.length-1], p) <= 0) lower.pop();
          lower.push(p);
        }
        const upper = [];
        for(let i=pts.length-1;i>=0;i--){
          const p = pts[i];
          while(upper.length>=2 && cross(upper[upper.length-2], upper[upper.length-1], p) <= 0) upper.pop();
          upper.push(p);
        }
        const hull = lower.slice(0,lower.length-1).concat(upper.slice(0,upper.length-1));
        contours.push(hull);
      }
    }
  }
  return contours;
}

/* ======= Ramer-Douglas-Peucker simplification ======= */
function rdp(points, eps){
  if(points.length < 3) return points.slice();
  const dist = (p, a, b) => {
    const A = a, B = b, P = p;
    const num = Math.abs((B[1]-A[1])*P[0] - (B[0]-A[0])*P[1] + B[0]*A[1] - B[1]*A[0]);
    const den = Math.hypot(B[1]-A[1], B[0]-A[0]);
    return den===0? Math.hypot(P[0]-A[0], P[1]-A[1]) : num/den;
  };
  let dmax=0, index=0;
  for(let i=1;i<points.length-1;i++){
    const d = dist(points[i], points[0], points[points.length-1]);
    if(d > dmax){ index=i; dmax=d; }
  }
  if(dmax > eps){
    const left = rdp(points.slice(0,index+1), eps);
    const right = rdp(points.slice(index), eps);
    return left.slice(0,-1).concat(right);
  } else {
    return [points[0], points[points.length-1]];
  }
}

/* ====== Chaikin smoothing (for advanced vector smoothing) ====== */
function chaikin(points, iterations=2){
  let pts = points.slice();
  for(let it=0; it<iterations; it++){
    const next = [];
    for(let i=0;i<pts.length;i++){
      const p0 = pts[i], p1 = pts[(i+1)%pts.length];
      next.push([ 0.75*p0[0] + 0.25*p1[0], 0.75*p0[1] + 0.25*p1[1] ]);
      next.push([ 0.25*p0[0] + 0.75*p1[0], 0.25*p0[1] + 0.75*p1[1] ]);
    }
    pts = next;
  }
  return pts;
}

/* ===== Helper: polygon to SVG path ===== */
function polyToPath(poly){
  if(!poly || poly.length===0) return '';
  const coords = poly.map(p => `${p[0].toFixed(2)} ${p[1].toFixed(2)}`).join(' L ');
  return `M ${coords} Z`;
}

/* ========= App logic ========= */
const fileInput = document.getElementById('fileInput');
const mainCanvas = document.getElementById('mainCanvas');
const overlayCanvas = document.getElementById('overlayCanvas');
const mainCtx = mainCanvas.getContext('2d');
const overlayCtx = overlayCanvas.getContext('2d');
let imgW=0, imgH=0, imageData=null;
let samples = []; // array of {rgb, hsv, pos}
let suggestions = []; // {contour, mask, accepted:false}
let finalObjects = []; // {poly, pngDataUrl, svgText}

function setStatus(msg){
  document.getElementById('status').textContent = msg;
}

/* Load image and resize to fit reasonably */
fileInput.addEventListener('change', (ev)=>{
  const f = ev.target.files && ev.target.files[0];
  if(!f) return;
  const reader = new FileReader();
  reader.onload = e=>{
    const img = new Image();
    img.onload = ()=>{
      // scale to max width 640 for better detail but mobile-friendly
      const maxW = 800;
      const maxH = 900;
      const ratio = Math.min(1, maxW / img.width, maxH / img.height);
      imgW = Math.round(img.width * ratio);
      imgH = Math.round(img.height * ratio);
      mainCanvas.width = overlayCanvas.width = imgW;
      mainCanvas.height = overlayCanvas.height = imgH;
      mainCtx.clearRect(0,0,imgW,imgH);
      mainCtx.drawImage(img, 0, 0, imgW, imgH);
      imageData = mainCtx.getImageData(0,0,imgW,imgH);
      overlayCtx.clearRect(0,0,imgW,imgH);
      samples = []; suggestions=[]; finalObjects=[];
      document.getElementById('suggestions').innerHTML=''; document.getElementById('objectList').innerHTML='';
      setStatus('Image loaded — tap to sample colors.');
    };
    img.src = e.target.result;
  };
  reader.readAsDataURL(f);
});

/* Pick color on tap */
mainCanvas.addEventListener('click', (ev)=>{
  if(!imageData) return;
  const rect = mainCanvas.getBoundingClientRect();
  const x = Math.floor((ev.clientX - rect.left) * (mainCanvas.width / rect.width));
  const y = Math.floor((ev.clientY - rect.top) * (mainCanvas.height / rect.height));
  const idx = (y*imgW + x)*4;
  const r = imageData.data[idx], g = imageData.data[idx+1], b = imageData.data[idx+2];
  const hsv = rgbToHsv(r,g,b);
  samples.push({rgb:[r,g,b], hsv:hsv, pos:[x,y]});
  drawSampleMarker(x,y);
  setStatus(`Sample ${samples.length} added — R${r} G${g} B${b}`);
});

/* Draw marker on overlay for selected sample */
function drawSampleMarker(x,y){
  overlayCtx.fillStyle = '#ff5757';
  overlayCtx.strokeStyle = '#fff';
  overlayCtx.lineWidth = 2;
  overlayCtx.beginPath(); overlayCtx.arc(x,y,6,0,Math.PI*2); overlayCtx.fill(); overlayCtx.stroke();
}

/* Build combined mask for selected samples using HSV tolerances */
function buildMask(){
  if(!imageData) return null;
  const w = imgW, h = imgH;
  const mask = new Uint8Array(w*h);
  if(samples.length===0) return mask;
  const tol = parseFloat(document.getElementById('tolerance').value);
  for(let y=0;y<h;y++){
    for(let x=0;x<w;x++){
      const i=(y*w + x)*4;
      const r = imageData.data[i], g = imageData.data[i+1], b = imageData.data[i+2];
      const hsv = rgbToHsv(r,g,b); // [0..360, 0..100, 0..100]
      for(const s of samples){
        // compare hue distance circularly
        const dh = Math.min(Math.abs(hsv[0]-s.hsv[0]), 360 - Math.abs(hsv[0]-s.hsv[0]));
        const ds = Math.abs(hsv[1] - s.hsv[1]);
        const dv = Math.abs(hsv[2] - s.hsv[2]);
        // weighted check: hue primary, allow wide sat/val tolerance based on tol
        const huePass = dh <= tol;
        const satPass = ds <= (tol*1.6);
        const valPass = dv <= (tol*1.6);
        if(huePass && satPass && valPass){ mask[y*w + x] = 1; break; }
      }
    }
  }
  return mask;
}

/* Generate suggestions: find contours from mask and produce suggested objects */
function generateSuggestions(){
  suggestions = [];
  overlayCtx.clearRect(0,0,imgW,imgH);
  const mask = buildMask();
  const minSize = parseInt(document.getElementById('minSize').value) || 50;
  const contours = maskToContours(mask, imgW, imgH);
  // filter small hulls by area approx (using bounding box)
  for(const c of contours){
    let minX=Infinity,minY=Infinity,maxX=-Infinity,maxY=-Infinity;
    for(const p of c){ if(p[0]<minX) minX=p[0]; if(p[1]<minY) minY=p[1]; if(p[0]>maxX) maxX=p[0]; if(p[1]>maxY) maxY=p[1]; }
    const area = (maxX-minX)*(maxY-minY);
    if(area < minSize) continue;
    // simplify hull
    const eps = parseFloat(document.getElementById('edgeSmooth').value) + 0.5;
    let simple = rdp(c, eps);
    // optionally advanced smoothing: Chaikin when toggled (but not yet accepted)
    const contourObj = {poly: simple, accepted: false, raw:c};
    suggestions.push(contourObj);
  }
  // show suggestions overlay
  drawSuggestions();
  // populate suggestion list UI
  renderSuggestionList();
}

/* Draw suggestion overlays (gray fill + dashed outline) */
function drawSuggestions(){
  overlayCtx.clearRect(0,0,imgW,imgH);
  const opacity = parseFloat(document.getElementById('suggOpacity').value);
  const dashThick = parseInt(document.getElementById('dashThick').value) || 2;
  overlayCtx.lineWidth = dashThick;
  overlayCtx.setLineDash([6,4]);
  overlayCtx.strokeStyle = 'rgba(40,40,40,1)';
  overlayCtx.fillStyle = `rgba(60,60,60,${opacity})`;
  for(let i=0;i<suggestions.length;i++){
    const s = suggestions[i];
    const poly = s.poly;
    if(!poly || poly.length<3) continue;
    overlayCtx.beginPath();
    overlayCtx.moveTo(poly[0][0], poly[0][1]);
    for(let j=1;j<poly.length;j++) overlayCtx.lineTo(poly[j][0], poly[j][1]);
    overlayCtx.closePath();
    overlayCtx.fill();
    overlayCtx.stroke();
    // label
    const cx = poly.reduce((a,p)=>a+p[0],0)/poly.length;
    const cy = poly.reduce((a,p)=>a+p[1],0)/poly.length;
    overlayCtx.fillStyle='white';
    overlayCtx.font='12px Arial';
    overlayCtx.fillText(`#${i+1}`, cx-6, cy+4);
    overlayCtx.fillStyle = `rgba(60,60,60,${opacity})`;
  }
}

/* Render list of suggestions with Accept/Reject */
function renderSuggestionList(){
  const el = document.getElementById('suggestions');
  el.innerHTML = '';
  suggestions.forEach((s, idx)=>{
    const div = document.createElement('div');
    div.className = 'suggestion';
    div.innerHTML = `<div style="font-weight:600">Suggestion #${idx+1}</div>
      <div style="display:flex;gap:6px;margin-top:6px">
        <button data-idx="${idx}" class="accept small">Accept</button>
        <button data-idx="${idx}" class="reject small">Reject</button>
      </div>`;
    el.appendChild(div);
  });
  // wire buttons
  el.querySelectorAll('button.accept').forEach(btn=>{
    btn.onclick = (ev)=>{
      const i = parseInt(ev.target.dataset.idx);
      acceptSuggestion(i);
    };
  });
  el.querySelectorAll('button.reject').forEach(btn=>{
    btn.onclick = (ev)=>{
      const i = parseInt(ev.target.dataset.idx);
      suggestions.splice(i,1);
      renderSuggestionList(); drawSuggestions();
    };
  });
}

/* Accept suggestion -> move to finalObjects (with optional smoothing/merge) */
function acceptSuggestion(i){
  const s = suggestions[i];
  if(!s) return;
  // optional vector smoothing
  let poly = s.poly.slice();
  if(document.getElementById('vecToggle').checked){
    const level = parseInt(document.getElementById('vecLevel').value);
    const iterations = Math.max(1, Math.round(level/25)); // map to smoothing passes
    poly = chaikin(poly, iterations);
  }
  // simplify again per user simplify level
  const simp = parseFloat(document.getElementById('edgeSmooth').value) || 1.0;
  poly = rdp(poly, simp);
  // record final object with png and svg
  const mask = polyToMask(poly, imgW, imgH);
  const pngCanvas = maskToCanvas(mask, imgW, imgH);
  const pngData = pngCanvas.toDataURL('image/png');
  const svg = generateSVGFromPolys([poly]);
  finalObjects.push({poly:poly, png:pngData, svg:svg});
  // remove suggestion
  suggestions.splice(i,1);
  drawSuggestions();
  renderFinalObjects();
  setStatus(`Accepted object — now ${finalObjects.length} final objects`);
}

/* poly->mask rasterization (scanline fill) returns Uint8Array mask */
function polyToMask(poly, w, h){
  const mask = new Uint8Array(w*h);
  if(!poly || poly.length<3) return mask;
  // find bounds
  let minY = h, maxY = 0;
  for(const p of poly){ minY = Math.min(minY, Math.floor(p[1])); maxY = Math.max(maxY, Math.ceil(p[1])); }
  minY = clamp(minY,0,h-1); maxY = clamp(maxY,0,h-1);
  // for each scanline, find intersections
  for(let y = minY; y<= maxY; y++){
    const nodes = [];
    for(let i=0;i<poly.length;i++){
      const a = poly[i], b = poly[(i+1)%poly.length];
      if((a[1] < y && b[1] >= y) || (b[1] < y && a[1] >= y)){
        const xint = a[0] + (y - a[1]) * (b[0]-a[0]) / (b[1]-a[1]);
        nodes.push(xint);
      }
    }
    nodes.sort((a,b)=>a-b);
    for(let k=0;k<nodes.length; k+=2){
      const xStart = Math.max(0, Math.floor(nodes[k]));
      const xEnd = Math.min(w-1, Math.ceil(nodes[k+1]));
      for(let x=xStart; x<=xEnd; x++) mask[y*w + x] = 1;
    }
  }
  return mask;
}

/* mask -> PNG canvas */
function maskToCanvas(mask, w, h){
  const c = document.createElement('canvas'); c.width = w; c.height = h;
  const cx = c.getContext('2d');
  const id = cx.createImageData(w,h);
  for(let i=0;i<mask.length;i++){
    if(mask[i]){
      const idx = i*4;
      id.data[idx] = imageData.data[idx];
      id.data[idx+1] = imageData.data[idx+1];
      id.data[idx+2] = imageData.data[idx+2];
      id.data[idx+3] = 255;
    } else {
      const idx = i*4; id.data[idx+3] = 0;
    }
  }
  cx.putImageData(id,0,0);
  return c;
}

/* produce SVG for given polygons list */
function generateSVGFromPolys(polys){
  const w = imgW, h = imgH;
  let paths = '';
  for(const p of polys){
    const path = polyToPath(p);
    paths += `<path d="${path}" fill="none" stroke="#000" stroke-width="1"/>`;
  }
  const svg = `<svg xmlns="http://www.w3.org/2000/svg" width="${w}" height="${h}">${paths}</svg>`;
  return svg;
}

/* render final objects UI */
function renderFinalObjects(){
  const list = document.getElementById('objectList');
  list.innerHTML = '';
  finalObjects.forEach((o, idx)=>{
    const div = document.createElement('div');
    div.className = 'thumb';
    div.innerHTML = `<img src="${o.png}" /><div style="margin-top:6px;display:flex;gap:6px;justify-content:center">
      <button data-idx="${idx}" class="btn small ghost" style="padding:6px">SVG</button>
      <button data-idx="${idx}" class="btn small ghost" style="padding:6px">PNG</button>
    </div>`;
    list.appendChild(div);
  });
  // attach handlers
  list.querySelectorAll('button').forEach(btn=>{
    btn.onclick = (ev)=>{
      const i = parseInt(ev.target.dataset.idx);
      if(ev.target.textContent.trim()==='SVG') downloadData(finalObjects[i].svg, 'image/svg+xml', 'object.svg');
      else downloadData(finalObjects[i].png, 'image/png', 'object.png');
    };
  });
}

/* download helper */
function downloadData(dataUrlOrText, mime, filename){
  // if dataUrl
  if(typeof dataUrlOrText === 'string' && dataUrlOrText.startsWith('data:')){
    const a = document.createElement('a');
    a.href = dataUrlOrText; a.download = filename; a.click();
    return;
  }
  // otherwise text (svg)
  const blob = new Blob([dataUrlOrText], {type:mime});
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a'); a.href = url; a.download = filename; a.click();
